import{_ as t,o as s,c as a,ag as i}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"AI diagnosis & failure clustering","description":"","frontmatter":{"title":"AI diagnosis & failure clustering","lang":"en-US"},"headers":[],"relativePath":"ai-diagnosis.md","filePath":"ai-diagnosis.md","lastUpdated":1782384032000}'),o={name:"ai-diagnosis.md"};function n(r,e,d,l,h,c){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="ai-diagnosis-failure-clustering" tabindex="-1">AI diagnosis &amp; failure clustering <a class="header-anchor" href="#ai-diagnosis-failure-clustering" aria-label="Permalink to &quot;AI diagnosis &amp; failure clustering&quot;">​</a></h1><p>When a run finishes, Piwi groups related failures and — optionally — asks an LLM to explain them. The two features work together: clustering decides <em>what</em> to diagnose, AI diagnosis explains <em>why</em> it broke.</p><h2 id="failure-clustering" tabindex="-1">Failure clustering <a class="header-anchor" href="#failure-clustering" aria-label="Permalink to &quot;Failure clustering&quot;">​</a></h2><p>Failed test cases that share the same <strong>error fingerprint</strong> are grouped into a cluster automatically. Instead of scrolling through 20 unrelated stack traces, you see something like <em>&quot;20 failures, 3 root causes.&quot;</em></p><ul><li><strong>Fingerprinting</strong> normalizes error messages so that the same underlying failure groups together across tests, spec files, and runs. Volatile fragments are masked out: timeouts and other numbers, UUIDs and hashes, URLs and emails, and both the <em>expected</em> and <em>received</em> values of an assertion. Dynamic locator options (e.g. the <code>{ name: &#39;…&#39; }</code> of a table row) are masked too, so per-row failures collapse into one cluster — while the locator target itself (the test id / role) still distinguishes genuinely different failures.</li><li>Fingerprints are <strong>call-site agnostic</strong>: the failing stack frame is shown for context but doesn&#39;t split clusters, so one root cause reached from several spec files stays a single cluster.</li><li>The run detail page shows each failure group with <strong>flaky</strong> and <strong>worker-correlation</strong> heuristics, so you can tell &quot;the app is broken&quot; from &quot;worker 3 is misbehaving.&quot;</li><li>Every cluster has its own <strong>detail page</strong> with the affected tests, triage tools (status + notes), and the AI diagnosis panel.</li></ul><p>Clustering is always on and requires no configuration. When the normalization algorithm is improved, existing clusters are migrated in place (re-fingerprinted from a stored sample error), so triage status, notes, and diagnoses survive the change. AI diagnosis is opt-in.</p><h3 id="semantic-merging-optional" tabindex="-1">Semantic merging (optional) <a class="header-anchor" href="#semantic-merging-optional" aria-label="Permalink to &quot;Semantic merging (optional)&quot;">​</a></h3><p>If an <strong>embedding</strong> model role is configured (Settings → AI), Piwi adds a semantic layer on top of the deterministic fingerprint. After a run, the clusters first seen in it are embedded and compared (cosine similarity) against the project&#39;s other open clusters; near-duplicates above <code>PIWI_CLUSTER_SIMILARITY_THRESHOLD</code> (default <code>0.92</code>) are merged into the longest-lived cluster. This catches failures that are the same root cause but phrased differently enough to dodge the fingerprint. Merges record a fingerprint alias so future occurrences attach to the survivor instead of re-forking. With no embedding role configured, clustering stays purely deterministic.</p><p>When auto-diagnose is enabled, new clusters are also given a short <strong>human-readable title</strong> (one cheap batched model call per run) shown in place of the raw normalized signature across the lists and the cluster page — the signature stays available on hover and below the title. Clusters fall back to the signature when no title has been generated.</p><p>Pairs that fall in the <strong>ambiguous band</strong> (similarity between <code>PIWI_CLUSTER_SUGGEST_THRESHOLD</code>, default <code>0.80</code>, and the merge threshold) aren&#39;t merged automatically. If a <strong>research</strong> model is configured it adjudicates the pair (&quot;same root cause?&quot;) and merges only on a high-confidence yes; otherwise — or when it&#39;s unsure — the pair becomes a <strong>merge suggestion</strong> on the project&#39;s Failure clusters tab, where a reporter or admin approves (merge) or dismisses it. Adjudication is budget-capped per run to control cost.</p><h2 id="enabling-ai-diagnosis" tabindex="-1">Enabling AI diagnosis <a class="header-anchor" href="#enabling-ai-diagnosis" aria-label="Permalink to &quot;Enabling AI diagnosis&quot;">​</a></h2><p>Configure a provider via <strong>Settings → AI</strong>, or with environment variables (env always takes precedence over values stored through the UI, and the UI shows env-managed fields read-only).</p><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_AI_PROVIDER</code></td><td><code>anthropic</code> or <code>openai</code></td></tr><tr><td><code>PIWI_AI_API_KEY</code></td><td>Provider API key (stored encrypted when set via the UI; never returned by the API)</td></tr><tr><td><code>PIWI_AI_MODEL</code></td><td>Model name (default: <code>claude-opus-4-8</code> for Anthropic)</td></tr><tr><td><code>PIWI_AI_BASE_URL</code></td><td>Base URL for OpenAI-compatible providers (e.g. Ollama, LM Studio, vLLM)</td></tr><tr><td><code>PIWI_AI_AUTO_DIAGNOSE</code></td><td><code>true</code> to automatically diagnose new clusters when a run finishes</td></tr><tr><td><code>PIWI_AI_RESEARCH_MODEL</code> / <code>_PROVIDER</code> / <code>_BASE_URL</code> / <code>_API_KEY</code></td><td>Optional <strong>research</strong> model for two-stage diagnosis; provider/base URL/key default to the main ones</td></tr><tr><td><code>PIWI_AI_EMBEDDING_PROVIDER</code> / <code>_MODEL</code> / <code>_BASE_URL</code> / <code>_API_KEY</code></td><td>Optional <strong>embedding</strong> model for semantic failure clustering (OpenAI-compatible only — Anthropic has no embeddings API)</td></tr></tbody></table><p><code>GET /api/ai/status</code> reports whether AI is configured (without ever exposing the key); the UI uses it to show or hide AI actions.</p><h3 id="model-roles" tabindex="-1">Model roles <a class="header-anchor" href="#model-roles" aria-label="Permalink to &quot;Model roles&quot;">​</a></h3><p>Piwi calls models in up to three distinct roles, each with its own complete provider configuration (or a <strong>reuse</strong> pointer to inherit another role&#39;s provider and credentials):</p><ul><li><strong>Diagnosis</strong> — the main model that writes the final diagnosis (required to enable AI).</li><li><strong>Research</strong> — an optional cheaper/faster model that pre-analyzes the failure first (<em>two-stage diagnosis</em>).</li><li><strong>Embedding</strong> — an optional embeddings model that powers semantic failure clustering.</li></ul><p>Configure each role in <strong>Settings → AI → Model providers</strong>. A role set to <em>reuse</em> another role uses that role&#39;s provider, key, and base URL — only its model can differ — so you don&#39;t re-enter credentials for, say, a Haiku research pass on the same Anthropic key.</p><h3 id="providers" tabindex="-1">Providers <a class="header-anchor" href="#providers" aria-label="Permalink to &quot;Providers&quot;">​</a></h3><p><strong>Anthropic (recommended)</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_PROVIDER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">anthropic</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sk-ant-...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">claude-opus-4-8</span></span></code></pre></div><p><strong>OpenAI</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_PROVIDER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">openai</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sk-...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gpt-4o</span></span></code></pre></div><p><strong>OpenAI-compatible / local (Ollama, etc.)</strong> — set <code>provider</code> to <code>openai</code> and point <code>base URL</code> at the local endpoint:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_PROVIDER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">openai</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_BASE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">http://localhost:11434/v1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_MODEL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">llama3.1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PIWI_AI_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ollama</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # any non-empty value for local servers</span></span></code></pre></div><p>Use <strong>Settings → AI → Test</strong> to smoke-test the configured provider.</p><h2 id="what-a-diagnosis-contains" tabindex="-1">What a diagnosis contains <a class="header-anchor" href="#what-a-diagnosis-contains" aria-label="Permalink to &quot;What a diagnosis contains&quot;">​</a></h2><p>A diagnosis is grounded in your actual run — it is not a generic &quot;ask AI&quot; button. Each result includes:</p><ul><li><strong>Category</strong> and <strong>confidence</strong></li><li><strong>Root cause</strong> — the most likely explanation</li><li><strong>Evidence</strong> — the signals the model relied on</li><li><strong>Suggested fix</strong> and <strong>prevention tips</strong></li></ul><h2 id="scm-grounded-context" tabindex="-1">SCM-grounded context <a class="header-anchor" href="#scm-grounded-context" aria-label="Permalink to &quot;SCM-grounded context&quot;">​</a></h2><p>The real power is feeding the model the code that changed. On a cluster page you can:</p><ul><li><strong>Pin a baseline commit</strong> — the diagnosis includes the aggregate diff between that commit and the run, so the model sees what changed.</li><li><strong>Browse and cherry-pick commits</strong> — add the full diff of specific commits to the context for targeted analysis.</li><li><strong>Preview the exact context</strong> that will be sent before running (<code>GET /api/failure-clusters/[id]/context</code>), so there are no surprises about what leaves your server.</li></ul><h2 id="custom-instructions" tabindex="-1">Custom instructions <a class="header-anchor" href="#custom-instructions" aria-label="Permalink to &quot;Custom instructions&quot;">​</a></h2><p>Tailor the analysis to your stack with <strong>global</strong> instructions (Settings → AI) and <strong>per-project</strong> instructions. Use them to describe your architecture, common false positives, or house style for fixes.</p><h2 id="context-limits-and-token-cost" tabindex="-1">Context limits (and token cost) <a class="header-anchor" href="#context-limits-and-token-cost" aria-label="Permalink to &quot;Context limits (and token cost)&quot;">​</a></h2><p>Every piece of evidence sent to the model costs tokens. Piwi caps each input so diagnoses stay fast and affordable. Defaults live in <code>shared/ai-context-limits.ts</code>; override them in <strong>Settings → AI</strong> or via env (env wins; the UI then shows the field read-only).</p><table tabindex="0"><thead><tr><th>Environment variable</th><th style="text-align:right;">Default</th><th>What it caps</th></tr></thead><tbody><tr><td><code>PIWI_AI_MAX_SAMPLE_ERROR_CHARS</code></td><td style="text-align:right;">3000</td><td>Characters of raw error text per error block</td></tr><tr><td><code>PIWI_AI_MAX_SCM_PATCH_BUDGET</code></td><td style="text-align:right;">4000</td><td>Total characters of diff patches across changed files</td></tr><tr><td><code>PIWI_AI_MAX_AFFECTED_TESTS</code></td><td style="text-align:right;">15</td><td>Affected tests listed</td></tr><tr><td><code>PIWI_AI_MAX_STEPS</code></td><td style="text-align:right;">30</td><td>Recent test steps included</td></tr><tr><td><code>PIWI_AI_MAX_CONSOLE_ENTRIES</code></td><td style="text-align:right;">15</td><td>Console error/warning entries</td></tr><tr><td><code>PIWI_AI_MAX_CONSOLE_ENTRY_CHARS</code></td><td style="text-align:right;">400</td><td>Characters per console entry</td></tr><tr><td><code>PIWI_AI_MAX_NETWORK_REQUESTS</code></td><td style="text-align:right;">15</td><td>Failed network requests included</td></tr><tr><td><code>PIWI_AI_MAX_ARIA_SNAPSHOT_CHARS</code></td><td style="text-align:right;">4000</td><td>Characters of the page ARIA snapshot</td></tr><tr><td><code>PIWI_AI_MAX_TEST_SOURCE_CHARS</code></td><td style="text-align:right;">3000</td><td>Characters of the test source snippet</td></tr><tr><td><code>PIWI_AI_MAX_SERVER_LOG_ENTRIES</code></td><td style="text-align:right;">30</td><td>Backend server log entries (from the <code>X-Piwi-Logs</code> header)</td></tr><tr><td><code>PIWI_AI_MAX_SERVER_LOG_ENTRY_CHARS</code></td><td style="text-align:right;">400</td><td>Characters per server log entry</td></tr><tr><td><code>PIWI_AI_MAX_IMAGES</code></td><td style="text-align:right;">3</td><td>Screenshots auto-included in the context</td></tr><tr><td><code>PIWI_AI_MAX_PASSED_PEERS</code></td><td style="text-align:right;">10</td><td>Passing peer tests in the same file listed</td></tr><tr><td><code>PIWI_AI_MAX_CONSOLE_WINDOW</code></td><td style="text-align:right;">30</td><td>Console entries (any level) in the window before failure</td></tr><tr><td><code>PIWI_AI_SLOW_REQUEST_MS</code></td><td style="text-align:right;">1500</td><td>Duration (ms) above which a network request is flagged as slow</td></tr></tbody></table><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>API keys are encrypted at rest with <a href="./configuration.html#general"><code>PIWI_SECRET_KEY</code></a>. When you run a diagnosis, the bounded context above is sent to your configured provider — so for fully local analysis, use Ollama or another self-hosted OpenAI-compatible model and keep everything on your own infrastructure.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./configuration.html">Configuration reference</a> — all environment variables</li><li><a href="./notifications.html">Notifications</a> — get alerted with <code>cluster.new</code> when a new cluster appears</li><li><a href="./mcp.html">MCP server</a> — let AI agents query clusters and diagnoses directly</li></ul>`,41)])])}const u=t(o,[["render",n]]);export{p as __pageData,u as default};
